        node,
        neighbors,
        links,
        facts,
      }),
    })
  );
});

const getFactsHandler = Effect.fn("KnowledgeGraphToolkit.GetFacts")(function* (params) {
  const graphiti = yield* GraphitiService;
  const facts = yield* graphiti.searchFacts({
    query: params.query,
