  const partsRef = yield* Ref.make(A.empty<ChatStreamPart>());

  const stream = LanguageModel.streamText({
    prompt: options.prompt,
    toolkit: KnowledgeGraphToolkit,
    toolChoice: "auto",
    concurrency: 1,
    disableToolCallResolution: true,
